INSERT INTO `akreditasi_instrumens` (`id`, `aspek_penilaian`, `kriteria`, `item_penilaian`, `item_terpenuhi`, `bukti_fisik`, `dokumen`, `created_at`, `updated_at`) VALUES
(13, 'Memiliki kebijakan tertulis pengembangan koleksi dan disahkan yang berwenang, yang memuat:', '2', '1)kriteria seleksi bahan perpustakaan\n2)jenis dan jumlah koleksi yang harus dimiliki\n3)kebijakan tentang koleksi khusus dan penambahan koleksi\n4)motode prolehan dan peruntukan koleksi\n5)evaluasi koleksi dan penyiangan\n6)sistem pemeliharaan dan pengendalian koleksi\n7)aspek lain terkait', '6', NULL, NULL, '2025-06-08 08:10:39', '2025-06-08 08:10:39'),
(14, 'jumlah kegiatan survei kebutuhan pemustaka yang dilakuakan oleh perpustakaan dalam 3 (tiga) tahun terakhir', '3', 'a. Lebih dari 4 kali\r\nb. 4 kali\r\nc. 3 kali\r\nd. 2 kali\r\ne. kurang dari 2 kali', 'A', NULL, NULL, '2025-06-08 08:12:08', '2025-06-08 08:12:08'),
(15, '1 - Jumlah kegiatan survei kebutuhan pemustaka yang dilakukan oleh perpustakaan dalam 3 (tiga) tahun terakhir', '4', 'a.Lebih dari 2.499 judul \r\nb.2.000 – 2.499 judul\r\nc.1.500 – 1.999  judul\r\nd.1.000 – 1.499  judul\r\ne.Kurang dari 1.000 judul', 'A', NULL, NULL, '2025-06-08 08:12:51', '2025-06-08 08:13:44'),
(16, '2 - Jenis koleksi referensi yang dimiliki (kamus, ensiklopedia, bibliografi, katalog, indeks, direktori, handbook/manual, statistik, atlas, globe, dll.)', '4', 'a.Lebih dari 8 jenis\r\nb.7 - 8 jenis\r\nc.5 - 6 jenis\r\nd.3 - 4 jenis\r\ne.Kurang dari 3 jenis', 'A', NULL, NULL, '2025-06-08 08:13:28', '2025-06-08 08:13:28'),
(17, '3 - Jumlah jurnal ilmiah tercetak yang dimiliki', '4', 'a. Lebih dari 3 judul \r\nb. 3 judul \r\nc. 2 judul \r\nd. 1 judul \r\ne. kurang dari 1 judul', 'A', NULL, NULL, '2025-06-08 08:14:22', '2025-06-08 08:14:22'),
(18, '4 - Jumlah koleksi terbitan instansi induk', '4', 'a. Lebih dari 150 judul \r\nb. 100 - 150 judul\r\nc. 50 - 99 judul\r\nd. 25 - 49 judul\r\ne. Kurang dari 25 judul', 'A', NULL, NULL, '2025-06-08 08:15:03', '2025-06-08 08:15:03'),
(19, '5 - Persentase jumlah penambahan koleksi (judul) rerata per tahun dalam 3 (tiga) tahun terakhir', '4', 'a. Lebih dari 4%\r\nb. 4%\r\nc. 3%\r\nd. 2%\r\ne. Kurang dari 2%', 'A', NULL, NULL, '2025-06-08 08:15:34', '2025-06-08 08:15:34'),
(20, 'Jumlah buku elektronik (e-books) yang dimiliki', '5', 'a. Lebih dari 499 judul\r\nb. 400 - 499 judul\r\nc. 300 - 399 judul\r\nd. 200 - 299 judul\r\ne. Kurang dari 200 judul', 'A', NULL, NULL, '2025-06-08 08:17:57', '2025-06-08 08:17:57'),
(21, '1 - Jenis kebijakan tertulis dalam pengorganisasian koleksi Perpustakaan yang dimiliki', '6', '1. Pedoman \r\n2. SOP \r\n3. Alur kerja \r\n4. Form/worksheet \r\n5. Manual sistem pengatalogan', 'A', NULL, NULL, '2025-06-08 08:19:15', '2025-06-08 08:19:15'),
(22, '2 - Penerapan standar/pedoman dalam pengorganisasian bahan perpustakaan; (1) deskripsi bibliografi, (2) klasifikasi, dan (3) tajuk subjekJenis-jenis bahan perpustakaan:', '6', '1)      Monograf\r\n2)      Serial\r\n3)      Kartografi\r\n4)      Sumber bahan elektronik\r\n5)      Bentuk mikro\r\n6)      Braille\r\n7)      Rekaman suara\r\n8)      Literatur kelabu\r\n9)      Rekaman video\r\n10)   Manuskrip', '10', NULL, NULL, '2025-06-08 08:20:11', '2025-06-08 08:20:11'),
(23, '1 - Sistem otomasi pengolahan koleksi perpustakaan dan pengorganisasian koleksi Perpustakaan, termasuk sistem “backup”', '8', 'a.Memiliki aplikasi otomasi baku lengkap yang didukung fasilitas LAN terkoneksi internet\r\nb.Memiliki aplikasi otomasi baku lengkap yang didukung fasilitas LAN\r\nc.Memiliki aplikasi otomasi baku dengan fasilitas stand alone\r\nd.Memiliki computer tetapi belum ada aplikasi otomasi    \r\ne.Belum memiliki', 'A', NULL, NULL, '2025-06-08 08:20:37', '2025-06-08 08:20:37'),
(24, '2 - Cacah ulang (stock opname) koleksi perpustakaan dilakukan secara reguler', '8', 'a. Kurang dari 2 tahun\r\nb. 2 tahun \r\nc. 3 tahun \r\nd. 4 tahun  \r\ne. Pernah tapi tidak regular', 'A', NULL, NULL, '2025-06-08 08:21:04', '2025-06-08 08:21:04'),
(25, '3 - Penyiangan (weeding) koleksi perpustakaan dilakukan secara reguler paling sedikit', '8', 'a. Kurang dari 2 tahun\r\nb. 2 tahun \r\nc. 3 tahun \r\nd. 4 tahun  \r\ne. Pernah tapi tidak regular', 'A', NULL, NULL, '2025-06-08 08:21:47', '2025-06-08 08:21:47'),
(26, '4 - Kegiatan pelestarian (perawatan dan perbaikan kerusakan) koleksi secara preventif dan kuratif seperti:', '8', '1) Pengaturan lingkungan  meliputi: pencahayaan, kebersihan, kelembaban\r\n2) Perbaikan koleksi rusak (perbaikan menambal, menjilid kembali)\r\n3) Pelestarian koleksi dan isi antara lain: meletakkan kapur barus, silica gel, dan alih media\r\n4) Penyampulan buku\r\n5) dan lain-lain', 'A', NULL, NULL, '2025-06-08 08:22:15', '2025-06-08 08:22:15'),
(27, '1 - Luas gedung/ruang perpustakaan yang dimiliki', '9', 'a.Lebih dari 174 m2 \r\nb.125 - 174 m2\r\nc.75 - 124 m2\r\nd.50 - 74 m2\r\ne.Kurang dari 50 m2', 'A', NULL, NULL, '2025-06-11 03:10:24', '2025-06-11 03:10:24'),
(28, 'Jumlah rak buku tercetak (termasuk koleksi referensi)', '10', 'a.Lebih dari 7 unit \r\nb.6 - 7 unit\r\nc.4 - 5 unit\r\nd.2 - 3 unit\r\ne.Kurang dari 2 unit', 'A', NULL, NULL, '2025-06-28 01:20:58', '2025-06-28 01:20:58'),
(29, 'Rak koleksi jurnal ilmiah dan majalah', '10', 'a.Lebih dari 2 unit \r\nb.2 unit\r\nc.1 unit\r\nd.1 unit (gabung dengan koleksi lain)\r\ne.Tidak memiliki', 'A', NULL, NULL, '2025-06-28 01:21:34', '2025-06-28 01:21:34'),
(30, 'Rak display koleksi buku baru', '10', 'a.Lebih dari 2 unit\r\nb.2 unit\r\nc.1 unit\r\nd.1 unit (gabungan dengan koleksi lain)\r\ne.Tidak memiliki', 'A', NULL, NULL, '2025-06-28 01:22:00', '2025-06-28 01:22:00'),
(31, 'Perangkat multimedia yang dimiliki:', '11', '1)Komputer yang terhubung internet \r\n2)LCD\r\n3)Scanner\r\n4)Printer\r\n5)VCD/DVD Player\r\n6)Televisi', '6', NULL, NULL, '2025-06-28 01:23:18', '2025-06-28 01:23:18'),
(32, 'Sarana layanan pemustaka meliputi:', '12', '1)Layanan baca ditempat\r\n2)Layanan informasi\r\n3)Layanan sirkulasi\r\n4)Layanan referensi\r\n5)Layanan konsultasi\r\n6)Layanan lain', '6', NULL, NULL, '2025-06-28 01:24:00', '2025-06-28 01:24:00'),
(33, 'Jumlah meja dan kursi baca', '12', 'a.Lebih dari 6 set\r\nb.5 - 6 set\r\nc.3 – 4 set\r\nd.2 set\r\ne.Kurang dari 2 set', 'A', NULL, NULL, '2025-06-28 01:24:23', '2025-06-28 01:24:23'),
(34, 'Jumlah papan pengumuman (konvensional dan elektronik /digital)', '12', 'a.Lebih dari 3 buah\r\nb.3 buah \r\nc.2 buah  \r\nd.1 buah \r\ne.Tidak ada', 'A', NULL, NULL, '2025-06-28 01:24:45', '2025-06-28 01:24:45'),
(35, 'Jumlah perangkat komputer yang dimiliki tenaga perpustakaan untuk kegiatan pengelolaan perpustakaan', '13', 'a.Lebih dari 3 unit \r\nb.3 unit\r\nc.2 unit\r\nd.1 unit\r\ne.Tidak ada', 'A', NULL, NULL, '2025-06-28 01:25:09', '2025-06-28 01:25:09'),
(36, 'Jumlah perangkat komputer untuk pemustaka', '13', 'a.Lebih dari 3 unit \r\nb.3 unit\r\nc.2 unit\r\nd.1 unit\r\ne.Tidak ada', 'A', NULL, NULL, '2025-09-13 07:14:41', '2025-09-13 07:14:41'),
(37, 'Kapasitas kecepatan akses internet (bandwidth) di perpustakaan', '13', 'a.Lebih dari 75 MBps\r\nb.50 – 75 MBps\r\nc.25 – 49 MBps\r\nd.5 – 24 MBps\r\ne.Kurang dari 5 MBps', 'A', NULL, NULL, '2025-09-13 07:15:10', '2025-09-13 07:15:10'),
(38, 'Jenis sarana keamanan gedung dan fasilitas perpustakaan', '14', '1)CCTV\r\n2)Pintu detektor\r\n3)Tempat penitipan barang/loker)\r\n4)Pintu darurat\r\n5)Alarm tanda bahaya\r\n6)Alat pemadam api\r\n7)Tenaga sekuriti', '7', NULL, NULL, '2025-09-13 07:15:56', '2025-09-13 07:15:56'),
(39, 'Fasilitas umum', '15', '1)Mushola \r\n2)Toilet \r\n3)Parkir\r\n4)Kantin\r\n5)Sarana difabel', '5', NULL, NULL, '2025-09-13 07:16:23', '2025-09-13 07:16:23'),
(40, 'Rambu-rambu perpustakaan yang tersedia', '15', '1)Papan nama perpustakaan\r\n2)Denah lokasi perpustakaan/petunjuk arah\r\n3)Denah ruang perpustakaan\r\n4)Papan nama ruang\r\n5)Direktori ruangan perpustakaan tercetak/elektronik', '5', NULL, NULL, '2025-09-13 07:16:46', '2025-09-13 07:16:46'),
(41, 'Jenis layanan perpustakaan:', '16', '1)Layanan baca di tempat\r\n2)Layanan sirkulasi\r\n3)Layanan referensi\r\n4)Layanan penelusuran\r\n5)Layanan literasi informasi\r\n6)Layanan penyediaan dokumen\r\n7)Layanan silang layan\r\n8)Layanan ekstensi', '8', NULL, NULL, '2025-09-13 07:17:59', '2025-09-13 07:17:59'),
(42, 'Kegiatan peningkatan layanan perpustakaan :', '16', '1)Survei kebutuhan layanan pemustaka\r\n2)Survei kepuasan pemustaka\r\n3)Diversifikasi layanan\r\n4)Layanan ekstensi', '4', NULL, NULL, '2025-09-13 07:18:25', '2025-09-13 07:18:25'),
(43, 'Jam buka perpustakaan per minggu', '17', 'a.Lebih dari 49 Jam\r\nb.45 – 49 jam\r\nc.40 – 44 jam\r\nd.35 – 39 jam\r\ne.Kurang dari 35 jam', 'A', NULL, NULL, '2025-09-13 07:18:46', '2025-09-13 07:18:46'),
(44, 'Sistem layanan sirkulasi', '18', 'a.Otomasi penuh/terintegrasi berbasis internet\r\nb.Otomasi penuh/terintegrasi berbasis LAN\r\nc.Manual dengan menggunakan sistem kartu\r\nd.Manual dengan sistem buku besar\r\ne.Tidak ada sistem sirkulasi', 'A', NULL, NULL, '2025-09-13 07:19:17', '2025-09-13 07:19:17'),
(45, 'Sistem akses informasi ke koleksi', '18', 'a.OPAC berbasis internet\r\nb.OPAC berbasis LAN\r\nc.Memiliki aplikasi otomasi (stand alone)\r\nd.Katalog kartu/buku\r\ne.Tidak ada katalog', 'A', NULL, NULL, '2025-09-13 07:19:39', '2025-09-13 07:19:39'),
(46, 'Fitur Website perpustakaan', '18', '1)Profil perpustakaan \r\n2)OPAC \r\n3)Informasi layanan perpustakaan \r\n4)Kontak perpustakaan \r\n5)Link ke basis data online/repositori\r\n6)Media sosial', '6', NULL, NULL, '2025-09-13 07:20:03', '2025-09-13 07:20:03'),
(47, 'Prosedur keanggotaan perpustakaan', '19', 'a.Registrasi online (terintegrasi kartu pegawai)\r\nb.Registrasi online \r\nc.Registrasi online dengan formulir permohonan\r\nd.Registrasi dengan sistem konvensional\r\ne.Tidak memiliki prosedur baku', 'A', NULL, NULL, '2025-09-13 07:20:22', '2025-09-13 07:20:22'),
(48, 'Jumlah rerata pengunjung  perpustakaan online dan/atau onsite per bulan dalam 1 (satu) tahun', '20', 'a.Lebih dari 600 orang \r\nb.500 – 600 orang\r\nc.400 – 499 orang\r\nd.300 – 399 orang\r\ne.Kurang dari 300 orang', 'A', NULL, NULL, '2025-09-13 07:20:50', '2025-09-13 07:20:50'),
(49, 'Jumlah rerata buku yang dipinjam per bulan dalam 1 (satu) tahun', '20', 'a.Lebih dari 499 eksemplar \r\nb.300 – 499 eksemplar\r\nc.100 - 299 eksemplar\r\nd.50 - 99 eksemplar\r\ne.Kurang dari 50 eksemplar', 'A', NULL, NULL, '2025-09-13 07:21:06', '2025-09-13 07:21:06'),
(50, 'Jenis kegiatan promosi yang dilaksanakan melalui media cetak dan elektronik:', '21', '1)Penyebaran informasi melalui berbagai media (tercetak dan elektronik),\r\n2)Penyuluhan (inklusi sosial), \r\n3)Lomba perpustakaan dan kepustakaan, \r\n4)Pameran perpustakaan dan kepustakaan,\r\n5)Bimbingan pemustaka\r\n6)dan lain-lain', '6', NULL, NULL, '2025-09-13 07:21:26', '2025-09-13 07:21:26'),
(51, 'Jumlah kegiatan promosi perpustakaan per tahun', '21', 'a.Lebih dari 7 kali \r\nb.7 kali\r\nc.6 kali\r\nd.5 kali\r\ne.Kurang dari 5 kali', 'A', NULL, NULL, '2025-09-13 07:22:07', '2025-09-13 07:22:07'),
(52, 'Kualifikasi pendidikan kepala perpustakaan', '22', 'a.S2 perpustakaan atau lebih tinggi\r\nb.S1 perpustakaan \r\nc.S1 bidang lain atau lebih tinggi dan diklat bidang perpustakaan\r\nd.Diploma Perpustakaan dan S1 bidang lain atau lebih tinggi dan belum mengikuti diklat bidang perpustakaan\r\ne.Diploma bidang lain', 'A', NULL, NULL, '2025-09-13 07:22:38', '2025-09-13 07:22:38'),
(53, 'Status kepala perpustakaan', '22', 'a.Fungsional pustakawan/profesional bidang perpustakaan \r\nb.Fungsional bidang lain dengan diklat bidang perpustakaan\r\nc.Fungsional bidang lain dan belum mengikuti diklat bidang perpustakaan\r\nd.Pegawai tetap nonfungsional\r\ne.Pegawai tidak tetap', 'A', NULL, NULL, '2025-09-13 07:22:55', '2025-09-13 07:22:55'),
(54, 'Jumlah Pengembangan Keprofesian Berkelanjutan (PKB) kepala perpustakaan di bidang perpustakaan dalam 3 (tiga) tahun terakhir', '22', '1)Sertifikat diklat manajemen perpustakaan\r\n2)Sertifikat diklat teknisperpustakaan\r\n3)Sertifikat kompetensi/profesi pustakawan\r\n4)Sertifikat bimtek/workshop, dll bidang kepustakawanan\r\n5)Sertifikat ....\r\n6)Sertifikat ....\r\n7)Sertifikat ....\r\n8)Sertifikat ....', '8', NULL, NULL, '2025-09-13 07:23:19', '2025-09-13 07:23:19'),
(55, 'Jumlah pustakawan (fungsional/profesional)', '23', 'a.Lebih dari 3 orang \r\nb.3 orang\r\nc.2 orang\r\nd.1 orang\r\ne.Belum ada', 'A', NULL, NULL, '2025-09-13 07:23:55', '2025-09-13 07:23:55'),
(56, 'Jumlah tenaga teknis', '24', 'a.Lebih dari 2 orang\r\nb.2 orang\r\nc.1 orang\r\nd.1 orang, merangkap unit lain\r\ne.Belum ada', 'A', NULL, NULL, '2025-09-13 07:24:19', '2025-09-13 07:24:19'),
(57, 'Tenaga Teknis bidang IT, minimal D3 bidang IT', '24', 'a.Lebih dari 2 orang\r\nb.2 orang\r\nc.1 orang \r\nd.1 orang latar belakang non IT \r\ne.Tidak ada', 'A', NULL, NULL, '2025-09-13 07:24:46', '2025-09-13 07:24:46'),
(58, 'Persentase jumlah tenaga perpustakaan yang berlatar belakang pendidikan minimal S1 perpustakaan dari keseluruhan tenaga perpustakaan', '24', 'a.Lebih dari 75% \r\nb.61 – 75%\r\nc.50 - 60%\r\nd.30 – 49%\r\ne.Kurang dari 30%', 'A', NULL, NULL, '2025-09-13 07:25:04', '2025-09-13 07:25:04'),
(59, 'Persentase jumlah pustakawan/tenaga perpustakaan yang mengikuti sertifikasi profesi pustakawan', '24', 'a.Lebih dari 49% \r\nb.40 - 49%\r\nc.30 - 39%\r\nd.20 - 29%\r\ne.Kurang dari 20%', 'A', NULL, NULL, '2025-09-13 07:25:24', '2025-09-13 07:25:24'),
(60, 'Jumlah rerata keikutsertaan tenaga perpustakaan dalam kegiatan Pengembangan Keprofesian Berkelanjutan (PKB) di bidang perpustakaan dalam 3 (tiga) tahun terakhir', '25', 'a.Lebih dari 4 kali\r\nb.4 kali\r\nc.3 kali\r\nd.2 kali\r\ne.Kurang dari 2 kali', 'A', NULL, NULL, '2025-09-13 07:25:40', '2025-09-13 07:25:40'),
(61, 'Persentase jumlah keikutsertaan tenaga perpustakaan dalam organisasi profesi', '26', 'a.Lebih dari 70% \r\nb.60 – 70 %\r\nc.50 – 59 %\r\nd.30 – 49%\r\ne.Kurang dari 30%', 'A', NULL, NULL, '2025-09-13 07:26:14', '2025-09-13 07:26:14');
