INSERT INTO `beritas` (`id`, `gambar`, `judul`, `slug`, `penulis`, `isi`, `created_at`, `updated_at`) VALUES
(4, 'czM1bCTxnQYkUJA699iNSAuIWdwm7hWt5ZxY0mun.jpg', 'Perpustakaan Ibrahimy Resmikan Pojok Baca Cabang Az-Zainiyah P2S2', 'perpustakaan-ibrahimy-resmikan-pojok-baca-cabang-az-zainiyah-p2s2', 'Yogy Asqinal R.', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p style=\"\" class=\"\"></p><div style=\"text-align: justify; \"><span style=\"text-align: var(--bs-body-text-align);\">Sukorejo, 9 Juni 2024 </span><span style=\"text-align: var(--bs-body-text-align);\">- Dalam rangka mewujudkan komitmen Universitas Ibrahimy untuk menjadikan tahun 2024 sebagai \"Tahun Literasi\", Perpustakaan Ibrahimy hari ini meresmikan Pojok Baca di Asrama Az Zainiyah. Peresmian ini dilakukan langsung oleh Rektor Universitas Ibrahimy, KH. Ach. Fadlail, S.H., M.H, dan dihadiri oleh Kepala Perpustakaan Ibrahimy beserta jajaranya, dan santri Asrama Az Zainiyah.</span></div><div style=\"text-align: justify;\"><span style=\"text-align: var(--bs-body-text-align);\">Pojok Baca ini merupakan wujud nyata dari dedikasi Universitas Ibrahimy dalam meningkatkan minat baca dan literasi, khususnya bagi para santri di Asrama Az Zainiyah. Pojok Baca ini dilengkapi dengan berbagai fasilitas, seperti rak buku yang terisi dengan koleksi buku-buku menarik dan inspiratif.</span></div><div style=\"text-align: justify;\"><span style=\"text-align: var(--bs-body-text-align);\">\"Pojok Baca ini diharapkan dapat menjadi oase bagi para santri untuk menimba ilmu dan pengetahuan melalui membaca,\" ujar KH. Ach. Fadlail, S.H., M.H dalam sambutannya. \"Kami berharap Pojok Baca ini dapat menjadi tempat yang nyaman dan kondusif bagi para santri untuk belajar dan mengembangkan diri.\"</span></div><div style=\"text-align: justify;\"><span style=\"text-align: var(--bs-body-text-align);\">Kepala Perpustakaan Ibrahimy ini juga menyampaikan bahwa Pojok Baca ini merupakan salah satu langkah awal dari program \"Tahun Literasi\" yang dicanangkan oleh Universitas Ibrahimy. Melalui program ini, Universitas Ibrahimy berkomitmen untuk menyelenggarakan berbagai kegiatan yang bertujuan untuk meningkatkan minat baca dan literasi di kalangan masyarakat, khususnya di Malang.</span></div><div style=\"text-align: justify;\"><span style=\"text-align: var(--bs-body-text-align);\">Peresmian Pojok Baca ini disambut dengan antusias oleh para santri Asrama Az Zainiyah. Mereka mengaku senang dengan adanya Pojok Baca ini dan berharap dapat memanfaatkannya dengan sebaik-baiknya</span></div><div style=\"text-align: justify;\"><span style=\"text-align: var(--bs-body-text-align);\">\"Saya senang sekali dengan adanya Pojok Baca ini,\" ujar salah satu santri. \"Sekarang saya bisa membaca buku-buku menarik dan menambah ilmu pengetahuan saya.\"</span></div><div style=\"text-align: justify;\"><span style=\"text-align: var(--bs-body-text-align);\">Diharapkan Pojok Baca ini dapat memberikan manfaat yang besar bagi para santri Asrama Az Zainiyah dan menjadi sumber inspirasi untuk meningkatkan minat baca dan literasi di Indonesia.</span></div><p></p></body></html>\n', '2024-06-09 14:20:10', '2024-12-02 09:40:40'),
(5, 'NRt8UyRFdKCRu3itwUEqrRLK5sMRgka0B8tSejSc.jpg', 'Perpustakaan Ibrahimy dengan Perpustakaan Universitas Islam Malang Tandatangani Kerjasama', 'perpustakaan-ibrahimy-dengan-perpustakaan-universitas-islam-malang-tandatangani-kerjasama', 'Ahmad Zeinuri', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><blockquote class=\"\"><div style=\"text-align: justify;\"><b style=\"background-color: var(--bs-card-bg); text-align: var(--bs-body-text-align);\">Malang, 26 Juli 2023 </b><span style=\"background-color: var(--bs-card-bg); text-align: var(--bs-body-text-align);\">- Perpustakaan Ibrahimy hari ini\r\nmenandatangani Nota Kesepahaman (MoU) dengan Perpustakaan Universitas Islam\r\nMalang (UIN Malang) dalam rangka meningkatkan kerjasama di bidang perpustakaan.\r\nMoU ini ditandatangani oleh Kepala Perpustakaan Ibrahimy, Bapak Muhammad Ali\r\nRidla, M.Kom, dan Kepala Perpustakaan UNISMA, Ibu Dra. Lilik Ernawati F., M.Si.</span></div><div style=\"text-align: justify;\"><span style=\"background-color: var(--bs-card-bg); text-align: var(--bs-body-text-align);\">Kerja sama ini bertujuan untuk:</span></div><ul style=\"scrollbar-color: var(--bs-scrollbar-hover-color) transparent;\"><li style=\"text-align: justify;\">meningkatkan akses informasi dan layanan perpustakaan bagi masyarakat luas</li></ul><ul style=\"scrollbar-color: var(--bs-scrollbar-hover-color) transparent;\"><li style=\"text-align: justify; \">Mengembangkan koleksi perpustakaan yang berkualitas dan berstandar internasional</li></ul><ul style=\"scrollbar-color: var(--bs-scrollbar-hover-color) transparent;\"><li style=\"text-align: justify;\">Meningkatkan sumber daya manusia pustakawan melalui pelatihan dan workshop</li></ul><ul style=\"scrollbar-color: var(--bs-scrollbar-hover-color) transparent;\"><li style=\"text-align: justify;\">Melakukan kegiatan bersama seperti seminar, konfrensi, dan pameran buku</li></ul><span style=\"line-height: 107%;\"><div style=\"text-align: justify;\"><span style=\"background-color: var(--bs-card-bg); text-align: var(--bs-body-text-align);\">MoU ini diharapkan dapat memberikan manfaat bagi kedua belah pihak,\r\nkhususnya dalam meningkatkan kualitas layanan perpustakaan dan literasi\r\nmahasiswa.</span></div></span><span style=\"line-height: 107%;\"><div style=\"text-align: justify;\"><span style=\"background-color: var(--bs-card-bg); text-align: var(--bs-body-text-align);\">Beberapa point penting dalam MoU ini antara lain:</span></div></span><ul><li style=\"text-align: justify;\">Perpustakaan Ibrahimy dan UIN Malang akan saling berbagi\r\nkoleksi perpustakaan</li></ul><ul><li style=\"text-align: justify;\">Kedua belah pihak akan melakukan pertukaran pustakawan untuk\r\nsaling belajar dan berbagi pengalaman</li></ul><ul><li style=\"text-align: justify;\">Perpustakaan Ibrahimy dan UIN Malang akan bekerjasama dalam\r\npenyelenggaraan kegiatan bersama, seperti seminar, konferensi, dan pameran\r\nbuku</li></ul><span style=\"line-height: 107%;\"><div style=\"text-align: justify;\"><span style=\"background-color: var(--bs-card-bg); text-align: var(--bs-body-text-align);\">MoU ini merupakan langkah penting bagi Perpustakaan Ibrahimy dan UIN\r\nMalang untuk meningkatkan kualitas layanan perpustakaan dan literasi mahasiswa.\r\nDiharapkan kerjasama ini dapat berjalan dengan baik dan memberikan manfaat yang\r\nbesar bagi semua pihak.</span></div></span></blockquote></body></html>\n', '2023-07-26 15:12:44', '2025-03-16 03:51:17'),
(6, 'xnfzhEUvTncPxUI1Bpw3NPkEHA1odEseRQNCs4eL.jpg', 'Perpustakaan Ibrahimy dan Perpustakaan nasional RI Tandatangani MoU untuk Perkuat Kolaborasi dan Pengembangan Perpustakaan di Era VUCA', 'perpustakaan-ibrahimy-dan-perpustakaan-nasional-ri-tandatangani-mou-untuk-perkuat-kolaborasi-dan-pengembangan-perpustakaan-di-era-vuca', 'Ahmad Zeinuri', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p style=\"text-align: justify; \"><span style=\"line-height: 107%;\"><b>Mojokerto, 30 Agustus 2024. </b>Dalam upaya memperkuat kolaborasi dan\r\npengembangan sumber daya perpustakaan, Perpustakaan Nasional Republik Indonesia\r\n(PERPUSNAS) bersama Forum Perpustakaan Perguruan Tinggi Indonesia (FPPTI) Jawa\r\nTimur melaksanakan penandatanganan Memorandum of Understanding (MoU) pada acara\r\nyang berlangsung di Varda Gardanei Hotel, Ketapanrame, Mojokerto, pada tanggal\r\n28-29 Agustus 2024.</span></p><p style=\"text-align: justify; \"><span style=\"line-height: 107%;\"><span style=\"line-height: 107%;\">Kegiatan ini dihadiri oleh perwakilan dari perguruan tinggi anggota\r\nFPPTI Jawa Timur, termasuk kepala perpustakaan universitas dan staf terkait,\r\nserta perwakilan dari Perpustakaan Nasional RI. Acara diawali dengan sambutan\r\ndari perwakilan PERPUSNAS, Ketua FPPTI Jawa Timur, dan Ketua Panitia.\r\nPenandatanganan MoU dilakukan sebagai bagian dari upaya untuk memperkuat\r\njaringan dan kolaborasi antara perpustakaan universitas dan Perpustakaan\r\nNasional.<br></span></span></p><p style=\"text-align: justify;\"><span style=\"line-height: 107%;\"><span style=\"line-height: 107%;\"><span style=\"line-height: 107%;\">Penandatanganan MoU ini bertujuan untuk meningkatkan akses terhadap\r\nsumber daya informasi yang lebih luas bagi pemustaka, baik di lingkungan\r\nuniversitas maupun masyarakat umum. Selain itu, MoU ini diharapkan dapat\r\nmeningkatkan kualitas layanan perpustakaan melalui berbagai program bersama\r\nseperti pelatihan, seminar, dan pengembangan koleksi.</span></span></span></p></body></html>\n', '2024-08-30 07:36:32', '2025-03-16 03:50:42'),
(7, 'wa51KjJdrnsNyDGu7YGmRQV6jNKZ1z6pvUvwXO2j.jpg', 'Perpustakaan Ibrahimy Hadiri Empowering Academic Research and Publishing On SDG\'s and the Library Support Workshop di Universitas Muhammadiyah Malang', 'perpustakaan-ibrahimy-hadiri-empowering-academic-research-and-publishing-on-sdgs-and-the-library-support-workshop-di-universitas-muhammadiyah-malang', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><font face=\"Arial, sans-serif\">Perpustakaan Universitas Muhammadiyah Malang&nbsp; mengadakan acara \"Empowering Academic Research and Publishing On SDG\'s and the Library Support Workshop\". Kegiatan tersebut dilaksanakan pada Rabu 12 Februari 2025, dengan keynote Speech Dr.Drs Joko Santoso, M. Hum (Sekretaris Utama Perpustakaan Republik Indonesia), untuk Pembicara Utama Prof. Dr. Indah Prihartini,&nbsp; MP.IPU (Dosen Universitas Muhammadiyah Malang) dan Shameem Nilofar Maiden (Pustakawan Singapore management University) dan Lee Pui Lee (Kepala Penjualan dan Kemitraan Tyairor Francis). Pada Acara&nbsp; tersebut di buka oleh Prof.Dr. Nazarrudin Malik, SE, MS.i selaku Rektor UMM dan Ian Jones (Wakil Presiden dan Pimpinan Komersial-APAC Taylor Francis). Beberapa pembicara juga mengisi pada acara workshop tersebut, adapun tempat pelaksanaannya di Aula GKB 4 Kampus 3 Universitas Muhammadiyah Malang.</font></body></html>\n', '2025-02-12 06:32:51', '2025-04-23 15:02:53'),
(8, 'zZxLQHP2IwRYBw2IjI9rfPzZo5WMU9DLmW7kSCEA.jpg', 'Perpustakaan Ibrahimy Mengadakan Seminar Entrepreneur', 'perpustakaan-ibrahimy-mengadakan-seminar-entrepreneur', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p class=\"MsoNormal\" style=\"text-align:justify\">Pada hari Kamis, 17 Oktober 2024,\r\ntelah dilaksanakan Seminar Entrepreneur dengan tema \"Santri Smartpreneur Integrasi\r\nIlmu Agama Dengan Kewirausahaan Digital\", bertempat di Aula Pondok\r\nPesantren Salafiyah Syafi\'iyah Sukorejo Lantai 2. Acara ini dihadiri oleh Mahasiswa\r\nUniversitas Ibrahimy, serta menghadirkan narasumber \"Moh Sulhan, S.T., M.Kom. Seorang Direktur Politeknik Universitas Islam Malang.</p><p></p><p></p><p class=\"MsoNormal\" style=\"text-align:justify\">Seminar dimulai pukul 13.00 WIB. dengan sambutan dari Pimpinan Perpustakaan Ibrahimy \"Muhammad Ali Ridla, M.Kom\".\r\ndilanjutkan dengan pemaparan materi oleh narasumber yang membahas Tentang Entrepreneur Setelah sesi pemaparan, acara dilanjutkan dengan sesi tanya jawab yang\r\nberlangsung secara interaktif.</p><p></p><p></p><p>\r\n\r\n\r\n\r\n</p><p class=\"MsoNormal\" style=\"text-align:justify\">Acara ditutup pada pukul 16.30 WIB. dengan kesimpulan dari moderator serta harapan agar ilmu yang didapat dapat\r\nditerapkan dalam dunia wirausaha.</p><p></p><p></p></body></html>\n', '2024-10-17 07:07:26', '2025-03-05 10:29:50'),
(9, 'nt732v2C1ZNHvoKzEQ0yszID6F7jNoGKBIaED9FR.jpg', 'Penyerahan Hibah Buku untuk Perpustakaan Ibrahimy', 'penyerahan-hibah-buku-untuk-perpustakaan-ibrahimy', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p class=\"MsoNormal\" style=\"\"><b>Sukorejo</b> - Sabtu (26/04) Perpustakaan Ibrahimy menerima hibah puluhan buku dari Bapak Badrus Soleh, S.H, Ketua LPBHNU Situbondo dan Ibu Atik Divisi Perlindungan Perempuan dan Anak (Div. PPA). Buku-buku yang diserahkan meliputi berbagai bidang ilmu, mulai dari agama, pendidikan, hingga tesis.</p><p class=\"MsoNormal\" style=\"\">Penyerahan secara simbolis dilakukan oleh Bapak Badrus Soleh, S.H, Ketua LPBHNU Situbondo kepada Wakil Rektor III Universitas Ibrahimy, Bapak Abdul Muqsit, M.Ling. di Kantor Universitas Ibrahimy. Dalam sambutannya, Bapak Abdul Muqsit, M.Ling. menyampaikan rasa syukur dan terima kasih atas dukungan tersebut, yang diharapkan dapat memperkaya koleksi dan meningkatkan minat baca para pengunjung.</p><p class=\"MsoNormal\" style=\"\">\"Kami sangat mengapresiasi bantuan ini. Buku-buku baru ini akan menjadi tambahan berharga bagi layanan kami kepada mahasiswa akademik maupun umum,\" ujarnya.</p><p class=\"MsoNormal\" style=\"\">Kegiatan ini menjadi bagian dari upaya memperkuat budaya literasi di lingkungan Pondok Pesantren Ibrahimy dan sekitarnya</p><div style=\"\"><br></div></body></html>\n', '2025-04-26 15:04:04', '2025-04-26 15:07:42'),
(10, 'xDQt7dL8W3lJLn7UdI7cUcuUiIPsVi1w9LqQH4Iv.jpg', 'Duta Baca dan Sahabat Baca Perpustakaan Ibrahimy', 'duta-baca-dan-sahabat-baca-perpustakaan-ibrahimy', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p><b>SUKOREJO</b> (26/07) Semangat literasi kembali digaungkan di lingkungan akademik Universitas Ibrahimy dengan terpilihnya Khoirul Anam sebagai Duta Baca dan Moh. Haikal sebagai Sahabat Baca Perpustakaan Ibrahimy 2024. Pemilihan ini merupakan bagian dari program tahunan yang diselenggarakan oleh Perpustakaan Ibrahimy, guna meningkatkan minat baca serta budaya literasi di kalangan mahasiswa.</p><p>Khoirul Anam mahasiswa Fakultas Dakwah dan Moh. Haikal mahasiswa Fakultas Syariah Ekonomi Islam, berhasil menyisihkan puluhan peserta lainnya melalui berbagai tahapan seleksi, mulai dari penulisan esai, presentasi program literasi, hingga sesi wawancara bersama dewan juri yang terdiri dari dosen Universitas Ibrahimy.</p><p>Dalam sambutannya, Kepala Perpustakaan Ibrahimy Muhammad Ali Ridla, M.Kom. menyampaikan bahwa Duta Baca Perpustakaan Ibrahimy bukan sekadar simbol, tetapi agen perubahan literasi di lingkungan kampus. \"Kami berharap Duta Baca dan Sahabat Baca terpilih mampu menginspirasi mahasiswa lain untuk menjadikan membaca sebagai bagian dari gaya hidup akademik mereka\", ujarnya.</p><p>Sebagai Duta Baca dan Sahabat Baca, Khoirul Anam dan Moh. Haikal akan menjalankan berbagai program yang akan mereka programkan.</p><p>Dalam pernyataannya Khoirul Anam menyatakan antusiasmenya untuk mengemban tugas ini. \"Saya percaya bahwa literasi bukan hanya tentang membaca, tapi juga berpikir kritis dan berbagi pengetahuan. Saya ingin menjadikan perpustakaan ibrahimy sebagai pusat kreativitas dan kolaborasi\",. ungkapnya.</p><p>Pemilihan Duta Baca perpustakaan ibrahimy ini diharapkan dapat menjadi langkah strategis dalam menciptakan ekosistem mahasiswa yang gemar membaca dan terus belajar sepanjang hayat. (red)</p><div><br></div></body></html>\n', '2024-07-26 15:09:17', '2025-07-26 07:36:04'),
(11, '16cpwJG2BcjQyiIh6fTPow2OB9o8qt21nNXM8T7K.jpg', 'Ngaji Puisi dalam rangka memperingati Hari Puisi Nasional di Perpustakaan Ibrahimy', 'ngaji-puisi-dalam-rangka-memperingati-hari-puisi-nasional-di-perpustakaan-ibrahimy', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p><b>Sukorejo</b> (28/04) telah diselenggarakan acara talk show dalam rangka memperingati hari puisi nasional, yang bertempat di Perpustakaan Ibrahimy, dan dihadiri oleh pengkhidmah dan pengunjung perpustakaan. Acara ini mengundang narasumber Bernama Ahmad Slamet (Suluk rasa) selaku orang yang bergelut dalam dunia puisi dan dimoderatori oleh Ach. Nurul Mustafa.</p><p>Moderator memberikan waktu kepada narasumber untuk memberikan pengalaman dan penjelasan mengenai adanya hari puisi. &acirc;&#128;&#156;Hari Puisi Nasional terjadi sebab hadirnya penyair nasiona bahkan internasional, guna untuk mengapresiasi para penyair pada waktu itu, yang salah satu tokohnya ialah Chairil Anwar (Si Binatang Jalang)\". Selain itu pembahasan puisi juga ditambahkan dalam sesi tersebut \"Puisi adalah kata-kata, serta disusun dengan indah (menurut D. Zawawi Imron), puisi yang bisa menggetarkan hati juga ditulis dengan sepenuh hati\".</p><p>Setelah itu, acara dilanjut dengan pembacaan puisi oleh pengunjung perpus, yang bernama Ach. Supriyadi dari Bogor dan Alif dari Kalimantan, serta pemberian buku kepada pembaca terbaik oleh narasumber.&nbsp;</p><p>Sebelum ditutup narasumber berpesan kepada pengunjung untuk mengejar cita-cita yang diinginkan selagi masih muda dan menulis apa yang dipikiran, sebab tidak akan ada yang tau di masa yang akan datang. (red)</p><div><br></div></body></html>\n', '2025-04-28 15:14:38', '2025-04-28 10:37:47'),
(12, '4QQLIs8KPrnS2fWcSRgQJIrVuYsoEQouG0dJ8sRE.png', 'Jelang HUT-RI, Pustakawan Asyik Menyulap Perpustakaan', 'jelang-hut-ri-pustakawan-asyik-menyulap-perpustakaan', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p class=\"MsoNormal\" style=\"text-align:justify;text-indent:36.0pt\"><b><span lang=\"EN-US\">S</span></b><b><span lang=\"IN\">UKOREJO </span></b><span lang=\"IN\">- M</span><span lang=\"EN-US\">enyambut Hari\r\nUlang Tahun Republik Indonesia ke-80, Perpustakaan Ibrahimy menampilkan suasana\r\nkemerdekaan yang berbeda dari biasanya. <b>Jum\'at (8/8)</b>, para pustakawan\r\nsecara kreatif menghias seluruh area perpustakaan dengan aksesori bernuansa\r\nmerah putih, mulai dari bendera mini, lampion, hingga mading yang berisi\r\ninformasi edukatif dan beragam quote para pejuang</span><span lang=\"IN\"> dan juga para masyaikh</span><span lang=\"EN-US\">.\r\nInisiatif ini dilakukan untuk memberikan pengalaman belajar yang lebih menarik\r\nbagi pengunjung, sekaligus menumbuhkan rasa cinta tanah air.</span></p><p></p><p></p><p class=\"MsoNormal\" style=\"text-align:justify;text-indent:36.0pt\"><span lang=\"EN-US\">Dekorasi ini merupakan bentuk penghargaan kami atas kiprah para\r\npendahulu. Perjuangan mereka harus kita hargai sedemikian berharga. Bentuk\r\nsemangat itu, ingin kami hadirkan di perpustakaan agar bisa dirasakan semua\r\norang, jelas Tsabitul Fajri, M.Pd., Kasubag Keuangan dan Inventaris.</span></p><p></p><p></p><p class=\"MsoNormal\" style=\"text-align:justify;text-indent:36.0pt\"><span lang=\"EN-US\">Respons pengunjung sangat positif. Banyak yang menilai bahwa\r\nperpustakaan semakin menarik, dan cerdas dalam memanfaatkan hari-hari historis. Vibe-nya merdeka banget, bikin betah buat berlama-lama di sini.</span></p><p></p><p></p><p>\r\n\r\n\r\n\r\n\r\n\r\n</p><p class=\"MsoNormal\" style=\"text-align:justify;text-indent:36.0pt\"><span lang=\"EN-US\">Kreativitas pustakawan berhasil menjadikan perpustakaan bukan hanya\r\nsebagai tempat membaca, tetapi juga sebagai sarana edukasi, inspirasi, dan\r\nrefleksi nasionalisme bagi seluruh pengunjung. (red)</span></p><p></p><p></p></body></html>\n', '2025-08-08 10:37:28', '2025-08-08 10:55:42'),
(13, 'MZY1eO9rK3Rtt73GAyzDtpdK8E04VaS6VyzjZAKM.jpg', 'VIDIO MOTIVATOR TALK PERINGATAN HARI KUNJUNG PERPUSTAKAAN', 'vidio-motivator-talk-peringatan-hari-kunjung-perpustakaan', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p class=\"MsoNormal\" style=\"text-align:justify;text-indent:1.0cm\"><span lang=\"EN-US\" style=\'font-family:\"Arial\",sans-serif;mso-ascii-theme-font:minor-bidi;\r\nmso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi\'>PERPUTAKAAN\r\nIBRAHIMY- (1</span><span lang=\"IN\" style=\'font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi;mso-ansi-language:IN\'>6</span><span lang=\"EN-US\" style=\'font-family:\r\n\"Arial\",sans-serif;mso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;\r\nmso-bidi-theme-font:minor-bidi\'>/09) bertepatan hari </span><span lang=\"IN\" style=\'font-family:\"Arial\",sans-serif;mso-ascii-theme-font:minor-bidi;\r\nmso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi;mso-ansi-language:\r\nIN\'>Selasa</span><span lang=\"EN-US\" style=\'font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi\'> diselenggarakannya acara literasi</span><span lang=\"EN-US\" style=\'font-family:\"Arial\",sans-serif;mso-ascii-theme-font:minor-bidi;\r\nmso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi;mso-ansi-language:\r\nIN\'> </span><span lang=\"EN-US\" style=\'font-family:\"Arial\",sans-serif;mso-ascii-theme-font:\r\nminor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi\'>dengan\r\nmenonton vidio sherlyannavita chanel motivator</span><span lang=\"IN\" style=\'font-family:\"Arial\",sans-serif;mso-ascii-theme-font:minor-bidi;\r\nmso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi;mso-ansi-language:\r\nIN\'> oleh Sherly Anavita Rahmi </span><span lang=\"EN-US\" style=\'font-size:12.0pt;\r\nline-height:107%;font-family:\"Times New Roman\",serif\'><p></p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;text-indent:1.0cm\"><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi;mso-ansi-language:IN\'>T</span><span lang=\"EN-US\" style=\'font-size:\r\n12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;mso-ascii-theme-font:\r\nminor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi\'>ujuan\r\nacara ini tidak lain agar memperluas dan memajukan wawasan literasi santri di </span><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi;mso-ansi-language:IN\'>P</span><span lang=\"EN-US\" style=\'font-size:\r\n12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;mso-ascii-theme-font:\r\nminor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi\'>erpustakaan\r\n</span><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi;mso-ansi-language:IN\'>I</span><span lang=\"EN-US\" style=\'font-size:\r\n12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;mso-ascii-theme-font:\r\nminor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi\'>brahimy\r\npondok pesantren salafiyah syafiiyah sukorejo <p></p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;text-indent:1.0cm\"><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi;mso-ansi-language:IN\'>D</span><span lang=\"EN-US\" style=\'font-size:\r\n12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;mso-ascii-theme-font:\r\nminor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi\'>engan\r\nHost khaerul anam sebagai duta baca perpustakaan ibrahimy di dalam acara ini\r\nada 3 vidio,yang pertama tentang sering minder, ini 5 tips untuk menumbuhkan\r\nrasa percaya diri dengan persentasi satu orang pengunjung, yang kedua ubah\r\ndirimu ubah masa depanmu dengan dua orang persentasi, yang ketiga bosan dengan\r\nkata-kata bijak dan motivasi</span><span lang=\"IN\" style=\'font-size:12.0pt;\r\nline-height:107%;font-family:\"Arial\",sans-serif;mso-ascii-theme-font:minor-bidi;\r\nmso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi;mso-ansi-language:\r\nIN\'>,</span><span lang=\"EN-US\" style=\'font-size:12.0pt;line-height:107%;\r\nfont-family:\"Arial\",sans-serif;mso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:\r\nminor-bidi;mso-bidi-theme-font:minor-bidi\'> dengan </span><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi;mso-ansi-language:IN\'>empat</span><span lang=\"EN-US\" style=\'font-size:\r\n12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;mso-ascii-theme-font:\r\nminor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi\'>\r\norang persentasi, dan masing masing vidio ada sesi persentasi yang berupa\r\nsharing ide dan kesimpulan<p></p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;text-indent:1.0cm\"><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi;mso-ansi-language:IN\'>O</span><span lang=\"EN-US\" style=\'font-size:\r\n12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;mso-ascii-theme-font:\r\nminor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi\'>leh\r\npara penonton</span><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;\r\nfont-family:\"Arial\",sans-serif;mso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:\r\nminor-bidi;mso-bidi-theme-font:minor-bidi;mso-ansi-language:IN\'>, </span><span lang=\"EN-US\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi\'>beberapa hari lalu tepatnya pada hari ahad diadakan pembagian kupon\r\nkepada pengu</span><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;\r\nfont-family:\"Arial\",sans-serif;mso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:\r\nminor-bidi;mso-bidi-theme-font:minor-bidi;mso-ansi-language:IN\'>n</span><span lang=\"EN-US\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi\'>jung yang berisi kritik saran kata kata motivasi&nbsp; untuk pepustakaan dalam rangka memperingati </span><b><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi;mso-ansi-language:IN\'>H</span></b><b><span lang=\"EN-US\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi\'>ari </span></b><b><span lang=\"IN\" style=\'font-size:12.0pt;line-height:\r\n107%;font-family:\"Arial\",sans-serif;mso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:\r\nminor-bidi;mso-bidi-theme-font:minor-bidi;mso-ansi-language:IN\'>K</span></b><b><span lang=\"EN-US\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi\'>unjung</span></b><b><span lang=\"IN\" style=\'font-size:12.0pt;\r\nline-height:107%;font-family:\"Arial\",sans-serif;mso-ascii-theme-font:minor-bidi;\r\nmso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi;mso-ansi-language:\r\nIN\'>an</span></b><b><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;\r\nfont-family:\"Arial\",sans-serif;mso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:\r\nminor-bidi;mso-bidi-theme-font:minor-bidi\'> </span></b><b><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi;mso-ansi-language:IN\'>P</span></b><b><span lang=\"EN-US\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi\'>erpustakaan</span></b><span lang=\"EN-US\" style=\'font-size:12.0pt;\r\nline-height:107%;font-family:\"Arial\",sans-serif;mso-ascii-theme-font:minor-bidi;\r\nmso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi\'>.<p></p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;text-indent:1.0cm\"><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi;mso-ansi-language:IN\'>K</span><span lang=\"EN-US\" style=\'font-size:\r\n12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;mso-ascii-theme-font:\r\nminor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:minor-bidi\'>emudian\r\nada sesi pembagian hadiah kepada pemenang undian dan bagi pengunjung yang\r\nmempersentasikan hasil pemikirannya dari video yang di tonton</span><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi;mso-ansi-language:IN\'>.</span><span lang=\"IN\" style=\'font-size:12.0pt;\r\nline-height:107%;font-family:\"Times New Roman\",serif;mso-ansi-language:IN\'><p></p></span></p><p class=\"MsoNormal\" align=\"right\" style=\"text-align:right\"><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-ansi-language:IN\'><p>&nbsp;</p></span></p><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p class=\"MsoNormal\" align=\"right\" style=\"text-align:right\"><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Arial\",sans-serif;\r\nmso-ascii-theme-font:minor-bidi;mso-hansi-theme-font:minor-bidi;mso-bidi-theme-font:\r\nminor-bidi;mso-ansi-language:IN\'>MRA<p></p></span></p></body></html>\n', '2025-09-16 07:25:32', '2025-09-16 07:25:32'),
(14, '2dx7iBdwiGhvt51NRgXxv2SYVhWYcnI26AC2e0lC.jpg', 'Pelatihan Penyusunan Makalah: Tingkatkan Keterampilan Mahasiswa Santri dalam Karya Tulis Ilmiah', 'pelatihan-penyusunan-makalah-tingkatkan-keterampilan-mahasiswa-santri-dalam-karya-tulis-ilmiah', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p class=\"\" style=\"text-align:justify\"><b><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi;mso-ansi-language:IN\'>Ibrahimy Library</span></b><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi;mso-ansi-language:IN\'>-(11/10) </span><span style=\'font-size:12.0pt;\r\nline-height:107%;font-family:\"Times New Roman\",serif;mso-fareast-font-family:\r\n\"Times New Roman\";mso-fareast-language:EN-ID\'>Telah dilaksanakan kegiatan <i>Pelatihan\r\nPenyusunan Makalah</i> yang diikuti oleh para santri dengan penuh antusias.\r\nKegiatan ini menghadirkan narasumber <b>Ubaidillah Ahmad, S.Kom.</b>, seorang </span><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-fareast-font-family:\"Times New Roman\";mso-ansi-language:IN;mso-fareast-language:\r\nEN-ID\'>mahasiswa Pascasarjana di Universitas Ibrahimy</span><span style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-fareast-font-family:\"Times New Roman\";mso-fareast-language:EN-ID\'>, serta\r\ndimoderatori oleh <b>Khoirul Abadi</b></span><b><span lang=\"IN\" style=\'font-size:\r\n12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;mso-fareast-font-family:\r\n\"Times New Roman\";mso-ansi-language:IN;mso-fareast-language:EN-ID\'>, S.Sos.</span></b><span style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-fareast-font-family:\"Times New Roman\";mso-fareast-language:EN-ID\'> yang\r\nmemandu jalannya acara dengan interaktif dan hangat.</span><span style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-fareast-font-family:\"Times New Roman\";mso-ansi-language:IN;mso-fareast-language:\r\nEN-ID\'> </span><span style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-fareast-font-family:\"Times New Roman\";mso-fareast-language:EN-ID\'>Dalam\r\npenyampaiannya, narasumber menjelaskan pentingnya kemampuan menulis makalah\r\nsecara sistematis, mulai dari penyusunan kerangka, pengolahan data, hingga\r\nteknik penulisan yang baik dan benar. Para peserta tampak aktif mengikuti sesi <i>tanya\r\njawab</i>, mengajukan berbagai pertanyaan seputar kesulitan dalam me</span><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-fareast-font-family:\"Times New Roman\";mso-ansi-language:IN;mso-fareast-language:\r\nEN-ID\'>nyusun makalah</span><span style=\'font-size:12.0pt;line-height:107%;\r\nfont-family:\"Times New Roman\",serif;mso-fareast-font-family:\"Times New Roman\";\r\nmso-fareast-language:EN-ID\'>.</span><span lang=\"IN\" style=\'font-size:12.0pt;\r\nline-height:107%;font-family:\"Times New Roman\",serif;mso-fareast-font-family:\r\n\"Times New Roman\";mso-ansi-language:IN;mso-fareast-language:EN-ID\'> Lalu k</span><span style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-fareast-font-family:\"Times New Roman\";mso-fareast-language:EN-ID\'>egiatan\r\nditutup dengan penyerahan <b>cinderamata</b> kepada narasumber sebagai bentuk\r\napresiasi atas ilmu dan motivasi yang telah diberikan.</span></p><p></p><p></p></body></html>\n', '2025-10-11 15:37:02', '2025-10-11 15:54:06'),
(15, '7jUXLGiKmlyFC5sUE9xtO9dKc04wXEcCG0fuK2eE.jpg', 'Kegiatan Bazar Tukar Buku (AZARKU) di perpustakaan Ibrahimy', 'kegiatan-bazar-tukar-buku-azarku-di-perpustakaan-ibrahimy', 'Izzil Muhiqqin, M.Tr.T.', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p class=\"MsoNormal\" style=\"text-align:justify\"><b><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi;mso-ansi-language:IN\'>Ibrahimy Library</span></b><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi;mso-ansi-language:IN\'>-(12/10) Perpustakaan Ibrahimy mengadakan\r\nkegiatan AZARKU (Bazar Tukar Buku), yang diikuti oleh pengunjung perpustakaan\r\ndengan menyerahkan bukunya dengan kartu tanda anggota kepada tenaga khidmah\r\nperpustakaan, acara ini juga bekerjasama dengan duta dan sahabat baca ibrahimy.\r\nDiadakan pada Ahad malam Senin yang bertempat di perpustakaan Ibrahimy yang\r\ndimulai pukul 21.00 sampai selesai dabn kegiatan ini hanya di adakan satu hari\r\n(<i>limitid edition</i>).<p></p></span></p><p class=\"MsoNormal\" style=\"text-align:justify\"><span lang=\"IN\" style=\'font-size:\r\n12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;mso-ascii-theme-font:\r\nmajor-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi;\r\nmso-ansi-language:IN\'>Konsep kegiatan ini dilakukan dengan penukaran buku milik\r\npengunjung dengan milik perpustakaan yang belum diinput, nantinya buku itu menjadi\r\nhak milik pengunjung yang menukar, buku yang ditukarpun bebas asalkan tidak\r\nmengandung unsur pornografi, serta kualitas buku masih bisa dipertanggung\r\njawabkan, seperti tidak sobek, halaman lengkap dan lain sebagainya.<p></p></span></p><p>\r\n\r\n\r\n\r\n</p><p class=\"MsoNormal\" align=\"right\" style=\"text-align:right\"><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi;mso-ansi-language:IN\'>MOHHA PS<p></p></span></p></body></html>\n', '2025-10-12 15:45:33', '2025-10-11 23:15:08'),
(16, 'F4FbZMlS0nCkipSpLdemfbLlVIDuIZjZZqP6r8Oz.jpg', 'Pelatihan Excel: Langkah Cerdas Santri Menuju Era Digital', 'pelatihan-excel-langkah-cerdas-santri-menuju-era-digital', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p class=\"MsoNormal\" style=\"text-align:justify\"><b><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi;mso-ansi-language:IN\'>Ibrahimy Library</span></b><span lang=\"IN\" style=\'font-size:12.0pt;line-height:107%;font-family:\"Times New Roman\",serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi;mso-ansi-language:IN\'>-(14/10) </span><span style=\'font-size:12.0pt;\r\nline-height:107%;font-family:\"Times New Roman\",serif;mso-fareast-font-family:\r\n\"Times New Roman\";mso-fareast-language:EN-ID\'>Dalam rangka meningkatkan\r\nkemampuan santri di bagian pengolahan data, telah diselenggarakan Pelatihan\r\nMicrosoft Excel yang diikuti dengan santri penuh antusias. Kegiatan ini\r\nmenghadirkan narasumber <b>Albi Guntara</b>, seorang mahasiswa fakultas sains\r\n&amp; tekonologi berpengalaman di bagian pengolahan data, serta dimoderatori\r\noleh saudara <b>Muhammad, S.H</b>., yang memandu jalannya acara dengan\r\ninteraktif dan komunikatif. Dalam materinya, narasumber memaparkan berbagai\r\nfitur penting dalam Microsoft Excel, mulai dari rumus dasar, pengolahan data,\r\nhingga penerapan fungsi-fungsi lanjutan untuk kebutuhan administrasi laporan\r\npertanggung jawaban bendahara kamar. Peserta tampak aktif mengikuti pelatihan,\r\nterutama saat sesi praktik langsung dan tanya jawab yang berlangsung hangat dan\r\npenuh antusiasme. Sebagai penutup, panitia memberikan cinderamata kepada\r\nnarasumber sebagai bentuk penghargaan dan terima kasih atas ilmu yang telah\r\ndibagikan.<p></p></span></p></body></html>\n', '2025-10-14 15:46:35', '2025-10-23 15:46:35'),
(17, 'Un2HmIvrifR6uMh6VO3ih3Fygn7jGZwhqpoOvlPh.png', 'Ngaji Desain: Melatih Santri Berkarya dengan Jiwa dan Goresan', 'ngaji-desain-melatih-santri-berkarya-dengan-jiwa-dan-goresan', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p class=\"MsoNormal\" style=\"text-align:justify\"><font face=\"Times New Roman, serif\"><span style=\"font-size: 16px;\">Ibrahimy Library- (15/10) Perpustakaan Ibrahimy mengadakan kegiatan ngaji desain yang dinarasumberi oleh Staf Perpustakaan Ibrahimy, yaitu Ach. Zainuri, S.Kom, dan dimoderatori oleh Muhammad Nur Hasyim. Kegiatan ini dimulai pukul 21.00 WIB, dengan acara pembukaan yang dilanjutkan dengan penyampaian materi berupa kaedah desain, warna dan tipografi (fon, konteras, dan jenis font) serta fungsi desain grafis, kemudian acara dilanjutkan dengan tanya jawab oleh peserta yang bernama Alfariza dan Andri, yang dilanjut dengan pelatihan di 17 rental komputer Perpustakaan Ibrahimy.</span></font></p><p class=\"MsoNormal\" style=\"text-align:justify\"><font face=\"Times New Roman, serif\"><span style=\"font-size: 16px;\">\"Desain itu simpel saja, agar tidak mengganggu apa yang mau disampaikan dalam hasilnya\" Ujar Zaenuri.</span></font></p><div style=\"text-align: justify;\"><br></div><p></p><p></p></body></html>\n', '2025-10-15 15:52:44', '2025-12-05 15:33:24'),
(18, 'wOGDHFhXHTdOeZDfr11YsTpHnvpKtfpbPm3XQDKI.png', 'NGOPI Episode 3 Pentingnya Membaca...!', 'ngopi-episode-3-pentingnya-membaca', 'Izzil Muhiqqin, M.Tr.T.', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p>IBRAHIMY LIBRARY - Pada Sabtu (25/10) Perpustakaan Ibrahimy mengadakan Acara Ngobrol Pintar Literasi (NGOPI) Episode 03. Kegiatan ini dipandu oleh Duta Baca Perpustakaan Ibrahimy, M. Khaerul Anam. Suasana akrab sangat terasa di perpustakaan pada malam itu, Acara ini memberikan kesempatan untuk bersantai namun tetap penuh makna, di mana peserta bisa bertukar ide, pengalaman, dan inspirasi terkait literasi dan dunia perpustakaan. Dalam sambutannya, menyampaikan harapan agar acara ini dapat mendorong budaya membaca dan berdiskusi dengan cara yang santai namun tetap berisi. Alhamdulillah, kita sejauh ini sudah komitmen mengadakan NGOPI. Bahkan, dihadiri secara antusias oleh seluruh pihak yang hadir. Bahwa, literasi ini benar-benar penting dan sangat menarik untuk terus dijadikan obrolan oleh kita semua ungkap Khoirul Anam dengan penuh semangat. Kegiatan ini dihadiri oleh pengurus majalah alqona\'ah dan al-khidmah. Mereka menunjukkan antusiasme saat mengikuti obrolan santai mengenai literasi. Selain diskusi yang tidak formal, acara ini juga ada sesi tanya jawab santai antara peserta dengan duta baca. Semakin hangat lagi, suasana ditambah dengan sajian es dan camilan ringan yang mengakrabkan peserta. Melalui acara NGOPI ini, Perpustakaan Ibrahimy menegaskan komitmennya untuk terus berinovasi dalam membangkitkan minat baca dan menjadikan perpustakaan sebagai ruang yang menyenangkan serta inspiratif bagi seluruh santri. Kami berkeinginan untuk menjadikan perpustakaan bukan sekadar tempat membaca, tetapi juga sarana untuk berdialog, serta menguatkan silaturrahmi antara kru majalah yang ada di pondok pesantren salafiyah syafi\'iyah, ujar salah satu staf perpustakaan. Di akhir acara, semua peserta berfoto bersama sebagai kenang-kenangan serta pembagian cindramata.</p></body></html>\n', '2025-10-24 17:40:44', '2025-12-05 23:14:56'),
(19, '1Lp01amwtjlp7vcY81QlUAuPBsjGwDhYGa8KvRn0.jpg', 'Bedah Buku \"Santri Jago Public Speaking\"', 'bedah-buku-santri-jago-public-speaking', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p>IBRAHIMY LIBRARY - Pada Sabtu (17/10) Dalam rangka meningkatkan kemampuan santri dalam bidang public speaking, perpustakaan ibrahimy mengadakan kegiatan bedah buku santri jago public speaking karya Moh. Nuril Anwar, M.Pd., M.Sos. beliau merupakan seorang dosen Komunikasi dan Penyiaran Islam Fakultas Dakwah Universitas Ibrahimy. Kegiatan ini menghadirkan langsung penulisnya untuk membedah buku tersebut. Antusiasme santri dalam mengikuti kegiatan tersebut sangat tinggi karena mereka merasa hal ini sangat penting untuk diikuti. Moch. Nuril Anwar mengatakan bahwa banyak santri yang stress dan juga banyak pula mahasiswa yang stress. Dikarenakan banyak santri dan mahasiswa yang bingung untuk menyampaikan ilmu yang dia punya ke khalayak umum. Seperti yang kita ketahui bahwa santri dituntut untuk melakukan pendampingan, pengayoman serta Pendidikan kepada masyarakat. Bagaimana santri akan melakukan hal itu semua jika santri tidak memahami bagaimana cara menyampaikan ilmu nya kepada masyarakat. Tentu hal ini menghambat jalan dakwah santri dalam mendidik masyarakat.</p><p>Dengan dimoderatori oleh Abdul Qodir Jaelani Haeron yang juga seorang mahasiswa KPI kegiatan berlangsung meriah dan seksama. Kegiatan ini terbagi menjadi tiga sesi. Sesi pertama ialah penyampaian materi oleh narasumber tentang highlight buku santri jago public speaking. Selanjutnya dilanjutkan dengan sesi kedua, yakni, tanya jawab antara narasumber dan peserta. Diakhir sesi penyerahan cinderamata dari Izzil Muhiqqin, M.Tr.T selaku Kabag. Layanan dan Literasi Perpustakaan Ibrahimy kepada narasumber.&nbsp;&nbsp;</p><p>Harapannya dengan diadakannya kegiatan bedah buku santri jago public speaking ini, para santri dan mahasiswa tidak kesusahan lagi untuk berdakwah dan mengamalkan ilmu nya di masyarakat.</p><div><br></div></body></html>\n', '2025-10-16 17:54:53', '2026-02-05 09:08:24'),
(20, 'VAsvC6QaSJMxJXaG7bRAGP6MDUhToDx4mEWqAno2.jpg', 'Pembukaan Library Class', 'pembukaan-library-class', 'Izzil Muhiqqin, M.Tr.T.', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p>PEMBUKAAN LIBRARY CLASS&nbsp;</p><p>LIBRAHIMY NEWS - Bertepatan tanggal 14 November telah diselenggarakan Rundown acara pembukaan library class yang bertempat di Perpustakaan Ibrahimy, pukul 20.30 WIB peserta mulai berdatangan dan mengisi presensi juga di berikan formulir feedback and lucky draw form yang diberikan oleh rizal sahabat baca, harapannya yaitu seperti apa expektasi peserta mengenai Libclass selanjutnya.</p><p>Acara ceremonial dipandu oleh Moh Haikal, dimulai dengan pembukaan, disusul dengan sambutan yang disampaikan oleh Izzil muhiqqin M.Tr.T. selaku Kabag teknis dan layanan pemustaka, mengantar peserta mengenai intelektual serta pentingnya class ini dan menegaskan Santri tidak hanya belajar spiritual tetapi juga intelektualnya, lalu dilanjutkan dengan penyampaian sambutan oleh M khaerul Anam selaku Duta baca, kemudian acara diteruskan dengan peresmian Library class serta pemngambilan foto Bersama Bapak Izzil Muhiqqin, terkahir acara ditutup dengan pembacaan doa yang dipimpin oleh Tsabitul fajri, M.pd. untuk harapan&nbsp; kedepan yang lebih baik dan berjalan dengan lancar.&nbsp; Kemudian acara ditutup oleh MC dilanjutkan sesi foto Bersama. Terakhir Anam menyampaikan arahan yang mungkin masih bingung diantara peserta Libclass.</p><p>Arzal s.</p></body></html>\n', '2025-11-14 16:41:06', '2025-12-05 23:14:44'),
(21, 'dpHc9gFDI1KyRC1vZ8gEp9BLRQpoLAgor26L1fGM.jpg', 'Fakultas Syariah Dan Ekonomi Islam Jalin Kerja Sama Dengan Perpustakaan Ibrahimy Sukorejo', 'fakultas-syariah-dan-ekonomi-islam-jalin-kerja-sama-dengan-perpustakaan-ibrahimy-sukorejo', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p>01 Desember 2025 Fakultas Syariah Dan Ekonomi Islam Resmi Menjalin Kerja Sama Dengan Perpustakaan Ibrahimy. Kolaborasi Ini Bertujuan Untuk Mengoptimalkan Akses Sumber Informasi Serta Pemanfaatan Fasilitas Yang Dimiliki Perpustakaan Ibrahimy, Sehingga Dapat Menunjang Peningkatan Kualitas Pembelajaran Dan Penelitian Di Lingkungan Fakultas. Dekan Fakultas Syariah Dan Ekonomi Islam, Arif Hariyanto, M.HI, Menyampaikan Bahwa Kerja Sama Ini Merupakan Bagian Dari Ikhtiar Fakultas Dalam Memperkuat Proses Pembelajaran Mahasiswa. \"Dengan Adanya Kerja Sama Ini, Mahasiswa Fakultas Syariah Dan Ekonomi Islam Diharapkan Memperoleh Pelayanan Yang Lebih Optimal Dari Perpustakaan Ibrahimy, Ujarnya\". Perjanjian Kerja Sama Tersebut Berjalan Lancar Dan Disepakati Dalam 16 Pasal, Di Antaranya Mengatur Mengenai Dasar Hukum, Maksud Dan Tujuan, Ruang Lingkup Kerja Sama, Serta Hak Dan Kewajiban Masing-Masing Pihak. Melalui Kerja Sama Ini, Kedua Institusi Berharap Dapat Saling Mendukung Dalam Meningkatkan Kualitas Akademik, Literasi, Dan Layanan Informasi Bagi Mahasiswa Maupun Sivitas Akademika Secara Lebih Luas.</p></body></html>\n', '2025-12-01 09:24:32', '2025-12-05 15:06:35');
INSERT INTO `beritas` (`id`, `gambar`, `judul`, `slug`, `penulis`, `isi`, `created_at`, `updated_at`) VALUES
(22, 'meAF3R5o3krPjcw6p5jZjOcEAES0VQJYqWCbZT9S.jpg', 'Pelatihan Cerita Pendek (CERPEN)', 'pelatihan-cerita-pendek-cerpen', 'Izzil Muhiqqin, M.Tr.T.', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p>LIBRAHIMY NEWS - Perpustakaan Ibrahimy, Jumat (05/12). Suasana malam di ruang utama perpustakaan terasa hangat ketika Short Story Workshop resmi dibuka pukul 21.00 WIB, dihadiri sekitar 60 peserta. Muhammad Khaerul Anam, Duta Baca yang juga bertindak sebagai moderator, memulai dengan sesi ice breaking untuk mencairkan suasana dan memusatkan perhatian peserta sebelum materi inti.</p><p>Setelah pengantar singkat, Anam membacakan CV narasumber, Muhammad Mukhlis, S.Pd.I., penulis cerpen berpengalaman, mantan pustakawan sejak MTs, dan dijuluki pembaca teladan di Perpustakaan Ibrahimy.</p><p>Dalam sesi materi, Mukhlis menekankan filosofi menulisnya: Lebih baik menulis lima cerpen daripada satu puisi, karena cerpen memberi ruang menata peristiwa, sementara puisi menuntut kepadatan kata. Ia menambahkan, Kalau blank atau lelah, berhenti menulis boleh, tapi jangan berhenti membaca. Banggalah jika kalian suka membaca, atau setidaknya bawa buku ke mana pun pergi. Apalagi sebagai mahasiswa, ini wajib.</p><p>Beliau berbagi pengalaman: karya cerpennya pernah meraih juara 1 FMCI. Ia menekankan pentingnya catatan harian (cathar), membayangkan karakter seolah nyata misalnya tokoh cantik ala \"Agnes Monica\" dan menyusun kerangka cerita yang jelas. Ide, menurutnya, bisa muncul kapan saja, bahkan di kamar mandi atau saat momen plong lainnya.</p><p>Sesi tanya jawab berlangsung interaktif, dengan peserta aktif mengajukan pertanyaan dan berdiskusi. Acara ditutup pukul 23.00 WIB dengan pemberian kenang-kenangan berupa buku antologi prosa karya LPMI dari Duta Baca kepada narasumber, diikuti foto bersama seluruh peserta, panitia, dan narasumber.</p><p>Di penutup, Mukhlis menegaskan, Bangga itu gratis, jadi berbanggalah dengan passion literasi kalian. Workshop ini diharapkan mendorong peserta konsisten menulis cerpen, mengasah kreativitas, dan memperkuat budaya literasi di pesantren. (RZL x SHL)</p></body></html>\n', '2025-12-04 22:55:43', '2025-12-07 23:34:14'),
(23, 'yxxKqNlATFTjjDIbw18elB2QfxbYqj5UdWZQvIdP.jpg', 'Materi Kepenulisan Angka Dan Bilangan', 'materi-kepenulisan-angka-dan-bilangan', 'Izzil Muhiqqin, M.Tr.T.', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p>Librahimy News - Library Class dan kelas Ibrahimi Corner menggelar pertemuan perdana bersama mentor M. Khaerul Anam pada Sabtu malam Ahad, 22/11, pukul 21.00 WIB. Kegiatan diawali dengan pengisian presensi. Peserta, yang didominasi mahasiswa, juga melakukan pengambilan buku pedoman kepenulisan dengan melengkapi formulir data peserta yang didampingi oleh Sahabat Baca, Rizal A.</p><p>Setelah itu, kelas dimulai. Antusiasme peserta begitu terasa melalui diskusi dan tanya jawab yang membuat suasana belajar mengalir dan hidup. Di akhir rangkaian materi, siswa Libclass diwajibkan mempresentasikan slide setiap bab sebagai evaluasi pemahaman. Dari 25 peserta yang hadir, terdapat 8 siswa yang berani tampil, di antaranya: Moh Ferdiansyah, Alvanza, Ahmad Jabaruddin, Ahmad Fauzan, Ikzam, Tio, Daffa, dan Alif.</p><p>Usai sesi presentasi, kegiatan dilanjutkan dengan menonton film pendek. Tujuannya sejalan dengan kelas BI Corner, yakni melatih peserta menghasilkan karya tulis melalui hikmah dan pesan yang mereka tangkap dari tayangan tersebut. Kelas kemudian ditutup dengan sesi foto bersama.</p><p>Arzal.s<span style=\"white-space:pre\">		</span></p></body></html>\n', '2025-11-21 23:12:18', '2025-12-07 23:35:35'),
(24, 'tSJ1GduKjexAl4z8msZrF1qDCcj7RI309AIDJZDy.jpg', 'Materi Tanda Baca dan Teknik Kepenulisan', 'materi-tanda-baca-dan-teknik-kepenulisan', 'Izzil Muhiqqin, M.Tr.T.', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p>LIBRAHIMY NEWS - membahas materi tanda baca dan teknik kepenulisan pada Ahad malam Senin, 23 November, di Perpustakaan Ibrahimy. Seperti biasa, kegiatan diawali dengan pengabsenan serta checklist data peserta yang didampingi oleh Rizal, Sahabat Baca.</p><p>Setelah itu, pembelajaran dilanjutkan dengan pemaparan power point yang dipandu oleh M. Khaerul Anam. Pada pertemuan kedua ini, para siswa LIB Class tampak lebih aktif dan antusias, baik dalam bertanya, berbagi pengalaman, presentasi, dan lain-lain. Di antaranya, Jabaruddin mengajukan pertanyaan mengenai penempatan tanda baca, sementara Nasim mempresentasikan struktur paragraf.</p><p>Kelas berlangsung dengan lancar. Setelah materi selesai, kegiatan dilanjutkan dengan menonton film pendek berjudul Mengharapkan, yang bercerita tentang balasan dari sebuah kebaikan. Kegiatan ini menjadi sarana penyegaran sekaligus pembelajaran, sesuai ketentuan awal bahwa peserta harus mengutip pesan bermakna dari film untuk kemudian dijadikan puisi berbeda dengan pertemuan pertama yang hanya membuat rangkaian kata.</p><p>Usai menonton film, kegiatan ditutup dengan sesi foto bersama.</p><div><br></div></body></html>\n', '2025-11-22 23:13:38', '2025-12-08 03:07:07'),
(25, 'w8ezt4XUNcoAgO75HTMcTPIEm9frw6ZexWdxvxJE.png', 'Mengolah Ide Menjadi Cerita', 'mengolah-ide-menjadi-cerita', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p>LIBRAHIMY NEWS-Pada Rabu (17/12), Perpustakaan Ibrahimy menggelar Novelette Workshop bersama Daniel Ahmad sebagai salah satu rangkaian kegiatan Library Class. Kegiatan ini merupakan agenda ke-16 dari total 20 kegiatan yang dijadwalkan dan masih menyisakan empat hari kegiatan lanjutan.</p><p>Workshop yang berlangsung mulai pukul 20.50 WIB hingga selesai tersebut diikuti oleh lebih dari 40 peserta. Acara dipandu oleh Muhammad selaku moderator yang mengarahkan jalannya kegiatan sejak pembukaan hingga akhir sesi.</p><p>Dalam pemaparan materinya, Daniel Ahmad mengajak peserta mendalami proses penulisan novelet secara komprehensif, mulai dari pencarian dan pengolahan ide, penentuan pesan dan genre, penyusunan kerangka cerita, hingga pengembangan alur, karakter, dan konflik secara konsisten dalam karya fiksi panjang.</p><p>Setelah penyampaian materi, kegiatan dilanjutkan dengan sesi tanya jawab yang berlangsung interaktif. Para peserta aktif mengajukan pertanyaan serta berdiskusi langsung dengan narasumber mengenai proses kreatif menulis, strategi pengembangan naskah, hingga kesiapan karya untuk dipublikasikan.</p><p>Sebagai bentuk apresiasi, civitas akademika Perpustakaan Ibrahimy menyerahkan cinderamata kepada narasumber atas kontribusi dan ilmu yang telah dibagikan. Selain itu, Duta Baca Perpustakaan Ibrahimy, yang juga merupakan salah satu kru Lembaga Pers Mahasiswa Ibrahimy, turut memberikan kenang-kenangan kepada Daniel Ahmad sebagai simbol penghargaan dan kolaborasi dalam penguatan gerakan literasi.</p><p>Rangkaian kegiatan kemudian ditutup dengan sesi foto bersama antara narasumber dan seluruh peserta. Melalui Novelette Workshop ini, Perpustakaan Ibrahimy terus menunjukkan komitmennya dalam menghadirkan ruang belajar literasi yang berkelanjutan melalui program Library Class, yang masih akan berlangsung hingga beberapa hari ke depan. (shl)</p></body></html>\n', '2025-12-23 17:21:57', '2026-02-05 09:07:30'),
(27, '4zGMMzYffbqE1fDufjo2cAYkPXklZayPSUxC9q20.jpg', 'Bedah Buku 100 Hujjah Aswaja Yang di Tuduh, Bid\'ah, Sesat, Syirik, Dan Kafir', 'bedah-buku-100-hujjah-aswaja-yang-di-tuduh-bidah-sesat-syirik-dan-kafir', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p>Pada Senin, 19 Januari 2025, Perpustakaan Ibrahimy menggelar kegiatan bedah buku di Aula Pondok Pesantren Salafiyah Syafiiyah. Kegiatan ini merupakan bagian dari rangkaian acara Festival Literasi Santri (FESRASA). Dalam kegiatan tersebut, Perpustakaan Ibrahimy menghadirkan langsung penulis buku, Kiai Maruf Khozin, dengan buku yang dibedah berjudul 100 Hujjah ASWAJA yang Dituduh Bidah, Sesat, Syirik, dan Kafir. Hadir sebagai pembanding Ustadz Kairuddin Habziz, M.HI, sementara Ahmad Muzayyin, S.Sy.,M.H dipercaya sebagai moderator. Ketua panitia, Albi Guntara, menyampaikan bahwa kegiatan bedah buku ini bertujuan untuk meningkatkan kualitas literasi santri. Selain menumbuhkan budaya literasi, bedah buku ini juga diharapkan dapat memperkuat pemahaman santri tentang akidah Ahlussunnah wal Jamaah ujarnya. Acara berlangsung dengan lancar dan diawali dengan rangkaian seremonial serta pembagian hadiah bagi para pemenang FESRASA putri, mengingat kegiatan bedah buku ini dikhususkan untuk santri putri. Sementara itu, pembagian hadiah bagi santri putra akan dilaksanakan terpisah, yakni untuk juara pertama pada malam Haflatul Imtihan Pondok Pesantren Salafiyah Syafiiyah, sedangkan juara dua dan tiga akan dibagikan pada acara penutupan Library Class.</p></body></html>\n', '2026-01-22 15:09:04', '2026-02-05 09:07:03'),
(28, 'nSIEYdrNIbLVeOw8u2NkiLdmPxHL3loJ5LEMoao5.jpg', 'Perpustakaan Ibrahimy Terima Hibah Buku dari Mohammad Mukhlis, S.Pd.I.', 'perpustakaan-ibrahimy-terima-hibah-buku-dari-mohammad-mukhlis-spdi', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p>Perpustakaan Ibrahimy Terima Hibah Buku dari Mohammad Mukhlis, S.Pd.I.</p><p>Jumat, 30 Januari 2026, Perpustakaan Ibrahimy menerima hibah buku sebanyak 8 judul bibliografi dengan total 86 eksemplar dari Bapak Mohammad Mukhlis, S.Pd.I. Hibah buku tersebut diserahkan bertepatan dengan rangkaian acara penutupan Library Class, di mana beliau juga hadir sebagai narasumber talk show.</p><p>Penyerahan buku dilakukan secara langsung oleh Bapak Mohammad Mukhlis, S.Pd.I. kepada Kepala Subbagian Keuangan dan Inventaris, Tsabitul Fajri, M.Pd. pada sesi penutupan acara. Kasubag Keuangan dan Inventaris menyampaikan rasa syukur dan terima kasih atas hibah buku yang diberikan kepada Perpustakaan Ibrahimy. \"Kami sangat bersyukur dan berterima kasih kepada Bapak Mukhlis atas hibah buku ini. Semoga menjadi ladang ibadah jariyah bagi beliau, serta dapat meningkatkan minat baca pengunjung dan memperkaya koleksi Perpustakaan Ibrahimy,\" ujarnya.&nbsp;</p><p>Penambahan koleksi buku ini diharapkan menjadi salah satu upaya dalam memperkuat budaya literasi di lingkungan Universitas Ibrahimy maupun Pondok Pesantren Salafiyah Syafi\'iyah Sukorejo, Situbondo.</p><p><br></p></body></html>\n', '2026-02-05 06:44:56', '2026-02-05 06:46:02'),
(29, 'yeMK0kuKzWgE2zh0c9R7IC3bm0ImqeO7W1IYFBU6.jpg', 'Santri Melek Digital', 'santri-melek-digital', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p>Perpustakaan Ibrahimy menggelar kegiatan Santri Melek Digital pada Selasa, 3 Februari 2026, yang bertempat di Perpustakaan Ibrahimi Putri. Kegiatan ini dipimpin oleh Bapak Moh. Ali Ridha, M.Kom., dengan narasumber Bapak Shohibul Migfar M.Pd. Acara diawali dengan pembacaan Surah Al-Ashr. Dalam pemaparannya, Bapak Shohibul Migfar menegaskan bahwa santri harus mampu berdakwah melalui media sosial dengan ciri khas santri sendiri. Dakwah di ruang digital, menurutnya, harus tetap memperhatikan etika dan aturan yang sesuai dengan syariat Islam. Media sosial perlu diimbangi dengan nilai-nilai syariat, agar tidak hanya dipenuhi oleh konten yang justru dapat menjerumuskan pada kemaksiatan. Kegiatan ini menjadi modal penting bagi santri Salafiyah Syafi\'iyah untuk mengembangkan dakwah di era digital. Tujuan utama kegiatan ini adalah membentuk santri yang cakap digital, berakhlak mulia, kritis, kreatif, serta mampu menjadi penjaga etika dan pelopor konten positif di ruang digital sesuai dengan visi pesantren. Kegiatan ini dihadiri oleh Pengurus Harian Rayon IKSASS Santri se-Nusantara, Pengurus Harian OSIS dan OSIM di lingkungan bidang Dikdasmen, Pengurus Harian BEMI, BEM Fakultas, serta BEM Ma\'had Aly. Acara berlangsung dengan lancar dan ditutup dengan doa.</p><div><br></div></body></html>\n', '2026-02-05 16:46:06', '2026-02-05 17:27:51'),
(30, 'VRq0D5eL5UM8NFhbC8hxUbSyrC0JmWYZnPaPINIh.jpg', 'Pelatihan Sitasi Ilmiah dengan menggunakan Mendeley', 'pelatihan-sitasi-ilmiah-dengan-menggunakan-mendeley', 'Syamsuddin, S.Kom', '<!DOCTYPE html PUBLIC \"-//W3C//DTD HTML 4.0 Transitional//EN\" \"http://www.w3.org/TR/REC-html40/loose.dtd\">\n<html><body><p class=\"MsoNormal\" align=\"center\" style=\"text-align: left;\"><span lang=\"IN\" style=\"text-align: justify;\">Kamis (5/2) Fakultas Dakwah dan Ushuluddin Universitas Ibrahimy mengadakan\r\nPelatihan Mendeley di Perpustakaan Ibrahimy. Pelatihan ini dikhususkan bagi\r\nmahasiswa semester akhir dari Prodi Komunikasi dan Penyiaran Islam (KPI) dan\r\nProdi Bimbingan dan Penyuluhan Islam (BPI). Hadir langsung sebagai narasumber\r\nyakni, Mohamad Tohir, M.Pd. seorang dosen Prodi Tadris Matematika Fakultas\r\nTarbiyah UNIB. Dalam penjelasannya beliau mengatakan bahwa Mendeley adalah\r\nperangkat lunak manajemen referensi berbasis open source dan jejaring sosial\r\nakademik yang dikembangkan oleh Elsevier. Alat ini digunakan untuk menyimpan,\r\nmengelola, memberi anotasi, dan membagikan dokumen penelitian, serta\r\nmempermudah pembuatan sitasi dan daftar pustaka otomatis dalam penulisan karya tulis\r\nilmiah. Baik itu skripsi, tesis, disertasi jurnal dll. Narasumber</span><span lang=\"EN-US\" style=\"text-align: justify;\"> yang juga salah satu anggota\r\nMendeley advisor Indonesia tersebut menjelaskan cara penulisan sitasi dengan\r\nstyle APA 7 (American Psychological Association Edisi ke-7) dengan menggunakan\r\naplikasi Mendeley. Dalam kesempatan tersebut dijelaskan satu persatu\r\ntahap-tahap pemasangan Mendeley hingga tata cara penggunaan Mendeley untuk&nbsp; keperluan skripsi mahasiswa.</span></p><p class=\"MsoNormal\" style=\"text-align: left;\"><span lang=\"EN-US\">Kegiatan pelatihan yang dimoderatori langsung\r\noleh Moh. Nuril Anwar, M.Pd., M.Sos. tersebut berjalan dengan lancar dan\r\nkomunikatif. Para peserta memperhatikan penjelasan dari narasumber dengan\r\nkhidmat dan seksama. Diakhir sesi terdapat beberapa pertanyaan dari peserta\r\ntentang bagaimana caranya jika memasukkan data wawancara ke Mendeley dan bagaimana\r\ncara membuat sitasinya. <p></p></span></p><p class=\"MsoNormal\" style=\"text-align: left;\"><span lang=\"EN-US\">Hingga pada pukul 14.55 WIB kegiatan pelatihan\r\ntersebut diakhiri dengan foto Bersama dan ditutup dengan doa.<p></p></span></p><p class=\"MsoNormal\" align=\"center\">\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p class=\"MsoNormal\" style=\"text-align:justify\"><span lang=\"IN\"><p>&nbsp;</p></span></p></body></html>\n', '2026-02-05 17:25:36', '2026-02-05 17:25:36');
